 35→  loadWasmPlugin,
 36→  runWasmGenerator,
 37→  clearWasmCache,
 38→} from "./wasm-generator.js";
 39→
 40→/** Supported capabilities for this frontend. */
 41→const SUPPORTED_CAPABILITIES = [
 42→  "analyze", "execute", "instrument", "setup", "generate",
 43→  "complex_type:date", "complex_type:date_time", "complex_type:duration",
 44→  "complex_type:reg_exp", "complex_type:url", "complex_type:big_int",
 45→  "complex_type:buffer", "complex_type:error", "complex_type:symbol",
 46→];
 47→
 48→/** Track the last analyzed file so execute can resolve function references. */
 49→let lastAnalyzedFile: string | null = null;
 50→
 51→/**
 52→ * Stored instrumented sources, keyed by "file:function".
 53→ * Set by the instrument handler, consumed by the execute handler.
 54→ */
 55→const instrumentedSources = new Map<string, string>();
 56→
 57→/**
 58→ * Loaded setup modules, keyed by file path.
 59→ * Cached so teardown can use the same module instance as setup.
 60→ */
 61→const loadedSetupModules = new Map<string, SetupModule>();
 62→
 63→/**
 64→ * Setup contexts from the most recent setup call, keyed by function name.
 65→ * Stored so teardown can pass the context back to the teardown function.
 66→ */
 67→const setupContexts = new Map<string, { module: SetupModule; context: unknown }>();
