 70→ * Dispatch a parsed request to the appropriate handler.
 71→ *
 72→ * Returns a Response and a shutdown flag. The handler is async because
 73→ * WASM generator loading requires awaiting plugin creation.
 74→ */
 75→export async function handleRequest(request: Request): Promise<{ response: Response; shutdown: boolean }> {
 76→  if (!isVersionCompatible(request.protocol_version)) {
 77→    return {
 78→      response: errorResponse(request.id, "version_mismatch",
 79→        `Unsupported protocol version: ${request.protocol_version} (expected ${PROTOCOL_VERSION})`),
 80→      shutdown: false,
 81→    };
 82→  }
 83→
 84→  switch (request.command) {
 85→    case "handshake":
 86→      return {
 87→        response: {
 88→          protocol_version: PROTOCOL_VERSION,
 89→          id: request.id,
 90→          status: "handshake",
 91→          frontend_version: PROTOCOL_VERSION,
 92→          language: FRONTEND_LANGUAGE,
 93→          capabilities: SUPPORTED_CAPABILITIES,
 94→        },
 95→        shutdown: false,
 96→      };
 97→
 98→    case "analyze": {
 99→      if (!fs.existsSync(request.file)) {
100→        return {
101→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
102→          shutdown: false,
103→        };
104→      }
105→
106→      lastAnalyzedFile = path.resolve(request.file);
107→      setProjectRoot(request.project_root);
108→      const functions = analyzeFile(request.file, request.function, request.project_root);
109→
110→      if (request.function != null && functions.length === 0) {
111→        return {
112→          response: errorResponse(
113→            request.id,
114→            "function_not_found",
115→            `Function not found: ${request.function} in ${request.file}`,
116→          ),
117→          shutdown: false,
118→        };
119→      }
120→
121→      return {
122→        response: {
123→          protocol_version: PROTOCOL_VERSION,
124→          id: request.id,
125→          status: "analyze",
126→          functions,
127→        },
128→        shutdown: false,
129→      };
130→    }
131→
132→    case "instrument": {
133→      if (!fs.existsSync(request.file)) {
134→        return {
135→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
136→          shutdown: false,
137→        };
138→      }
139→
140→      const source = fs.readFileSync(request.file, "utf-8");
141→      const result = instrumentFunction(source, request.function, request.file);
142→
143→      if ("error" in result) {
144→        return {
145→          response: errorResponse(request.id, "instrumentation_failed", result.error),
146→          shutdown: false,
147→        };
148→      }
149→
150→      // Store the instrumented source for use by the execute handler.
151→      // Use resolved path so keys match execute's resolved fileForExec.
152→      const key = `${path.resolve(request.file)}:${request.function}`;
153→      instrumentedSources.set(key, result.instrumentedSource);
154→      lastAnalyzedFile = path.resolve(request.file);
155→
156→      return {
157→        response: {
158→          protocol_version: PROTOCOL_VERSION,
159→          id: request.id,
160→          status: "instrument",
161→          instrumented: true,
162→          output_file: null,
163→          instrumentable_line_count: result.instrumentableLineCount,
164→        },
165→        shutdown: false,
166→      };
167→    }
168→
169→    case "execute": {
170→      const funcRef = request.function;
171→      const fileForExec = resolveFileForExecute(funcRef);
172→
173→      if (!fileForExec) {
174→        return {
175→          response: errorResponse(
176→            request.id,
177→            "function_not_found",
178→            `Cannot resolve file for function: ${funcRef}. Use file:function format.`,
179→          ),
180→          shutdown: false,
181→        };
182→      }
183→
184→      try {
185→        // Check if we have instrumented source for this function
186→        const funcName = funcRef.includes(":") ? funcRef.split(":").pop()! : funcRef;
187→        const instrumentKey = `${fileForExec}:${funcName}`;
188→        const instrumentedSource = instrumentedSources.get(instrumentKey);
189→
190→        let rawResult;
191→        if (instrumentedSource) {
192→          rawResult = await executeInstrumented(instrumentedSource, funcName, request.inputs, request.mocks ?? [], fileForExec);
193→        } else {
194→          rawResult = await executeFunction(fileForExec, funcRef, request.inputs);
195→        }
196→
197→        return {
198→          response: buildExecuteResponse(request.id, PROTOCOL_VERSION, rawResult),
199→          shutdown: false,
200→        };
201→      } catch (e: unknown) {
202→        const msg = e instanceof Error ? e.message : String(e);
203→        return {
204→          response: errorResponse(request.id, "internal_error", `Execute failed: ${msg}`),
