215→        };
216→      }
217→
218→      try {
219→        let setupModule = loadedSetupModules.get(request.file);
220→        if (!setupModule) {
221→          setupModule = loadSetupModule(request.file);
222→          loadedSetupModules.set(request.file, setupModule);
223→        }
224→
225→        const setupContext = runSetup(setupModule, request.function, request.mode);
226→        setupContexts.set(request.function, { module: setupModule, context: setupContext });
227→
228→        return {
229→          response: {
230→            protocol_version: PROTOCOL_VERSION,
231→            id: request.id,
232→            status: "setup",
233→            setup_context: setupContext,
234→          },
235→          shutdown: false,
236→        };
237→      } catch (e: unknown) {
238→        const msg = e instanceof Error ? e.message : String(e);
239→        return {
240→          response: errorResponse(request.id, "internal_error", `Setup failed: ${msg}`),
241→          shutdown: false,
242→        };
243→      }
244→    }
245→
246→    case "teardown": {
247→      try {
248→        const stored = setupContexts.get(request.function);
249→        if (!stored) {
250→          return {
251→            response: errorResponse(
252→              request.id,
253→              "internal_error",
254→              `No setup context found for function: ${request.function}. Call setup first.`,
255→            ),
256→            shutdown: false,
257→          };
258→        }
259→
260→        runTeardown(stored.module, request.function, stored.context);
261→        setupContexts.delete(request.function);
262→
263→        return {
264→          response: {
265→            protocol_version: PROTOCOL_VERSION,
266→            id: request.id,
267→            status: "teardown_ack",
268→          },
269→          shutdown: false,
270→        };
271→      } catch (e: unknown) {
272→        const msg = e instanceof Error ? e.message : String(e);
273→        return {
274→          response: errorResponse(request.id, "internal_error", `Teardown failed: ${msg}`),
275→          shutdown: false,
276→        };
277→      }
278→    }
279→
280→    case "generate": {
281→      if (!fs.existsSync(request.file)) {
282→        return {
283→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
284→          shutdown: false,
285→        };
286→      }
287→
288→      try {
289→        if (request.file.endsWith(".wasm")) {
290→          const plugin = await loadWasmPlugin(request.file);
291→          const result = await runWasmGenerator(plugin, request.name, request.recipe);
292→
293→          return {
294→            response: {
295→              protocol_version: PROTOCOL_VERSION,
296→              id: request.id,
297→              status: "generate",
298→              value: result.value,
299→              generator_id: result.id,
300→              ...(result.recipe !== undefined ? { recipe: result.recipe } : {}),
301→            },
302→            shutdown: false,
303→          };
304→        }
305→
306→        const generatorModule = loadGeneratorModule(request.file);
307→        const value = runGenerator(generatorModule, request.name, request.kind);
308→
309→        return {
310→          response: {
311→            protocol_version: PROTOCOL_VERSION,
312→            id: request.id,
313→            status: "generate",
314→            value,
315→            generator_id: "generated",
316→          },
317→          shutdown: false,
318→        };
319→      } catch (e: unknown) {
320→        const msg = e instanceof Error ? e.message : String(e);
321→        return {
322→          response: errorResponse(request.id, "internal_error", `Generate failed: ${msg}`),
323→          shutdown: false,
324→        };
325→      }
326→    }
327→
328→    case "shutdown":
329→      await clearWasmCache();
330→      return {
331→        response: {
332→          protocol_version: PROTOCOL_VERSION,
333→          id: request.id,
334→          status: "shutdown_ack",
335→        },
336→        shutdown: true,
337→      };
338→  }
339→}
340→
341→/**
342→ * Resolve the file path for an execute request.
343→ *
344→ * The function reference can be in "file:function" format or just a function name.
345→ * If just a name, falls back to the last analyzed file.
346→ */
347→function resolveFileForExecute(funcRef: string): string | null {
348→  if (funcRef.includes(":")) {
349→    // file:function format — extract the file part
350→    const lastColon = funcRef.lastIndexOf(":");
351→    const file = funcRef.substring(0, lastColon);
352→    if (fs.existsSync(file)) {
353→      return path.resolve(file);
354→    }
355→  }
356→
357→  // Fall back to last analyzed file (already resolved on store)
358→  return lastAnalyzedFile;
359→}
360→
361→function isVersionCompatible(version: string): boolean {
362→  // For now, require exact match on major.minor
363→  const [reqMajor, reqMinor] = version.split(".").map(Number);
364→  const [ourMajor, ourMinor] = PROTOCOL_VERSION.split(".").map(Number);
365→  return reqMajor === ourMajor && reqMinor === ourMinor;
366→}
367→
368→function errorResponse(id: number, code: ErrorResponse["code"], message: string): ErrorResponse {
369→  return {
370→    protocol_version: PROTOCOL_VERSION,
371→    id,
372→    status: "error",
373→    code,
374→    message,
375→  };
376→}
377→
378→/**
379→ * Parse a JSON string into a Request, returning an error response if invalid.
380→ */
381→export function parseRequest(line: string): { request: Request } | { error: ErrorResponse } {
382→  let parsed: unknown;
383→  try {
384→    parsed = JSON.parse(line);
385→  } catch {
386→    return {
387→      error: errorResponse(0, "invalid_request", `Invalid JSON: ${line.slice(0, 100)}`),
388→    };
389→  }
390→
391→  if (typeof parsed !== "object" || parsed === null) {
392→    return {
393→      error: errorResponse(0, "invalid_request", "Request must be a JSON object"),
394→    };
395→  }
396→
397→  const obj = parsed as Record<string, unknown>;
398→
399→  if (typeof obj["id"] !== "number") {
400→    return {
401→      error: errorResponse(0, "invalid_request", "Request must have a numeric 'id' field"),
402→    };
403→  }
404→
405→  const id = obj["id"] as number;
406→
407→  if (typeof obj["protocol_version"] !== "string") {
408→    return {
409→      error: errorResponse(id, "invalid_request", "Request must have a 'protocol_version' string field"),
410→    };
411→  }
412→
413→  if (typeof obj["command"] !== "string") {
414→    return {
415→      error: errorResponse(id, "invalid_request", "Request must have a 'command' string field"),
416→    };
417→  }
418→
419→  const validCommands = ["handshake", "analyze", "instrument", "execute", "setup", "teardown", "generate", "shutdown"];
420→  if (!validCommands.includes(obj["command"] as string)) {
421→    return {
422→      error: errorResponse(id, "invalid_request", `Unknown command: ${String(obj["command"])}`),
423→    };
424→  }
425→
426→  return { request: parsed as Request };
427→}
428→
429→/**
430→ * Clear stored instrumented sources and setup state. Useful for testing.
431→ */
432→export function clearInstrumentedSources(): void {
433→  instrumentedSources.clear();
434→  loadedSetupModules.clear();
435→  setupContexts.clear();
436→}
