141→/**
142→ * Transpile a TypeScript file to JavaScript and return the exports object.
143→ *
144→ * Results are cached by absolute file path.
145→ */
146→function loadModule(filePath: string): Record<string, unknown> {
147→  const absolutePath = path.resolve(filePath);
148→  const cached = compiledModuleCache.get(absolutePath);
149→  if (cached) return cached;
150→
151→  const source = fs.readFileSync(absolutePath, "utf-8");
152→  const result = ts.transpileModule(source, {
153→    compilerOptions: {
154→      target: ts.ScriptTarget.ES2022,
155→      module: ts.ModuleKind.CommonJS,
156→      esModuleInterop: true,
157→      strict: true,
158→      jsx: ts.JsxEmit.ReactJSX,
159→    },
160→    fileName: absolutePath,
161→  });
162→
163→  const targetRequire = wrapRequireWithReactShim(createRequire(absolutePath), absolutePath);
164→  const moduleExports: Record<string, unknown> = {};
165→  const moduleObj = { exports: moduleExports };
166→
167→  const sandbox = vm.createContext({
168→    module: moduleObj,
169→    exports: moduleExports,
170→    require: targetRequire,
171→    console: consoleProxy,
172→    process,
173→    Buffer,
174→    setTimeout,
175→    clearTimeout,
176→    setInterval,
177→    clearInterval,
178→    __filename: absolutePath,
179→    __dirname: path.dirname(absolutePath),
180→  });
