192→/**
193→ * Look up a function from the file path and function name.
194→ *
195→ * The function name may be a simple name like "classifyNumber" which is
196→ * looked up directly on the module exports. If it contains a colon
197→ * (file:function format from the analyze phase), the file portion is
198→ * stripped and only the function name is used.
199→ */
200→function resolveFunction(
201→  filePath: string,
202→  functionRef: string,
203→): (...args: unknown[]) => unknown {
204→  // Strip file prefix if present (e.g. "examples/foo.ts:myFunc" → "myFunc")
205→  const funcName = functionRef.includes(":")
