315→/**
316→ * Truncate a message string to fit within maxBytes.
317→ * If truncated, appends a suffix indicating the message was cut.
318→ */
319→export function truncateMessage(msg: string, maxBytes: number = MESSAGE_MAX_BYTES): string {
320→  const bytes = Buffer.byteLength(msg, "utf-8");
321→  if (bytes <= maxBytes) return msg;
322→  const suffix = "…[truncated]";
323→  const suffixBytes = Buffer.byteLength(suffix, "utf-8");
324→  const target = maxBytes - suffixBytes;
325→  let end = Math.min(msg.length, target);
326→  while (Buffer.byteLength(msg.slice(0, end), "utf-8") > target && end > 0) {
327→    end--;
328→  }
329→  return msg.slice(0, end) + suffix;
330→}
331→
332→/**
333→ * Truncate console_output side effects if they exceed head+tail line limits.
334→ * Returns the (possibly truncated) effects array and truncation metadata.
335→ */
336→export function truncateSideEffects(
337→  effects: SideEffect[],
338→  headLines: number = CAPTURE_HEAD_LINES,
339→  tailLines: number = CAPTURE_TAIL_LINES,
340→): { effects: SideEffect[]; truncation?: TruncationInfo } {
341→  const consoleIndices: number[] = [];
342→  for (let i = 0; i < effects.length; i++) {
343→    const effect = effects[i];
344→    if (effect !== undefined && effect.kind === "console_output") {
345→      consoleIndices.push(i);
346→    }
347→  }
348→
349→  const consoleCount = consoleIndices.length;
350→  if (consoleCount <= headLines + tailLines) {
351→    return { effects };
352→  }
353→
354→  let originalBytes = 0;
355→  for (const idx of consoleIndices) {
356→    const e = effects[idx];
357→    if (e !== undefined && e.kind === "console_output") {
358→      originalBytes += Buffer.byteLength(e.message, "utf-8");
359→    }
360→  }
361→
362→  const keepHead = new Set(consoleIndices.slice(0, headLines));
363→  const keepTail = new Set(consoleIndices.slice(-tailLines));
364→  const truncatedCount = consoleCount - headLines - tailLines;
365→
366→  let keptBytes = 0;
367→  for (const idx of [...keepHead, ...keepTail]) {
368→    const e = effects[idx];
369→    if (e !== undefined && e.kind === "console_output") {
370→      keptBytes += Buffer.byteLength(e.message, "utf-8");
371→    }
372→  }
373→  const truncatedBytes = originalBytes - keptBytes;
374→
375→  const result: SideEffect[] = [];
376→  let markerInserted = false;
377→  for (let i = 0; i < effects.length; i++) {
378→    const effect = effects[i];
379→    if (effect === undefined) continue;
380→    if (effect.kind !== "console_output") {
381→      result.push(effect);
382→    } else if (keepHead.has(i)) {
383→      result.push(effect);
384→    } else if (keepTail.has(i)) {
385→      result.push(effect);
386→    } else if (!markerInserted) {
387→      result.push({
388→        kind: "console_output",
389→        level: "info",
390→        message: `[…truncated ${truncatedCount} lines / ${truncatedBytes} bytes…]`,
391→      });
392→      markerInserted = true;
393→    }
394→  }
395→
396→  return {
397→    effects: result,
398→    truncation: {
399→      was_truncated: true,
400→      original_lines: consoleCount,
401→      original_bytes: originalBytes,
402→    },
403→  };
404→}
