      expect(parsed.scope_events![1]).toEqual({
        type: "branch",
        decision: { branch_id: 0, line: 3, taken: true, constraint: { kind: "unknown", hint: "test" } },
      });
      expect(parsed.scope_events![3]).toEqual({ type: "scope", event: { kind: "call_enter", call_site_id: 1 } });
    }
  });

});

